import { useEffect, useState } from "react";
import axios from "axios";
import DashboardShell from "./components/DashboardShell";
import KpiGrid from "./components/KpiGrid";
import CategoryPie from "./components/CategoryPie";
import TrendLineChart from "./components/TrendLineChart";
import InsightsPanel from "./components/InsightsPanel";

const api = axios.create({
  baseURL: "http://127.0.0.1:8000/api",
  timeout: 10000,
});

function App() {
  const [summary, setSummary] = useState(null);
  const [categories, setCategories] = useState(null);
  const [monthlyTrend, setMonthlyTrend] = useState(null);
  const [healthScore, setHealthScore] = useState(null);
  const [insights, setInsights] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchData() {
      try {
        setLoading(true);
        const [summaryRes, categoriesRes, trendRes, healthRes, insightsRes] =
          await Promise.all([
            api.get("/summary"),
            api.get("/categories"),
            api.get("/monthly-trend"),
            api.get("/health-score"),
            api.get("/insights"),
          ]);

        setSummary(summaryRes.data);
        setCategories(categoriesRes.data.categories);
        setMonthlyTrend(trendRes.data.monthly_trend);
        setHealthScore(healthRes.data.health_score);
        setInsights(insightsRes.data.insights);
      } catch (err) {
        setError(
          err.response?.data?.detail || "Unable to load analytics data."
        );
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, []);

  return (
    <DashboardShell loading={loading} error={error}>
      {summary && (
        <KpiGrid summary={summary} healthScore={healthScore} />
      )}
      <div className="grid gap-6 xl:grid-cols-[1.4fr_1fr]">
        <CategoryPie categories={categories} />
        <TrendLineChart monthlyTrend={monthlyTrend} />
      </div>
      <InsightsPanel insights={insights} />
    </DashboardShell>
  );
}

export default App;
